UPDATE public.cms_arcanos SET
  essencia = 'Os Enamorados é o Arcano VI — o momento sagrado da escolha consciente. Não se trata apenas de romance: é o encontro com o outro que revela quem somos. É a encruzilhada onde cabeça e coração precisam se alinhar, onde escolher é também renunciar. Sob a bênção do anjo Rafael, os Enamorados nos lembram que toda grande decisão é, no fundo, uma decisão sobre quem queremos ser. Reencenação do mito edênico — Adão, Eva e o anjo entre as árvores do Conhecimento e da Vida — eleva o desejo humano à categoria de via espiritual: amar é assumir uma direção. Sob a bênção do anjo, escolher é também consagrar.',
  simbolos_centrais = 'Anjo Rafael: Bênção divina, cura e proteção sobre a escolha — o amor como força espiritual

Homem e mulher nus: Vulnerabilidade, autenticidade e transparência — nada a esconder

Árvore da Vida (atrás do homem): Os doze frutos — as doze possibilidades da experiência humana

Árvore do Conhecimento (atrás da mulher): A serpente e o fruto proibido — consciência, tentação e sabedoria

Montanha ao centro: O desafio que a união precisa escalar juntos — o caminho ascendente

Sol radiante: Clareza, verdade e calor — a luz que ilumina a escolha',
  luz = 'Na luz, Os Enamorados representam amor verdadeiro, escolhas alinhadas com valores profundos, harmonia entre razão e emoção, e a coragem de se comprometer. É o momento em que você escolhe não pelo medo, mas pelo desejo genuíno. Aplicados, traduzem-se em parcerias que crescem juntas, decisões éticas tomadas em encruzilhadas reais e a integridade rara de quem alinha sentimento, palavra e ato. Quando encontrados na luz, indicam alinhamento interno, relações autênticas e decisões que honram quem você realmente é.',
  sombra = 'Na sombra, Os Enamorados se tornam indecisão paralisante, escolhas feitas por pressão externa, relações baseadas em projeção, ou a recusa de escolher para não perder nenhuma opção. Na sombra, eles perguntam: você está escolhendo com o coração ou evitando a responsabilidade de decidir?',
  amor = 'Na luz: No amor, Os Enamorados indicam conexão profunda e autêntica, atração mútua com base em valores compartilhados, e o momento de escolher conscientemente estar com alguém. Pode representar uma relação que transforma, um reencontro significativo, ou a decisão de se abrir ao amor.

Na sombra: Na sombra amorosa, avisam sobre triângulos amorosos, indecisão entre duas pessoas, relações baseadas em idealização, ou a incapacidade de se comprometer por medo de perder a liberdade.',
  trabalho = 'Na luz: No trabalho, Os Enamorados falam de parcerias estratégicas, decisões de carreira que refletem valores pessoais, e alinhamento entre o que você faz e o que acredita. É a escolha profissional feita com o coração, não apenas com o bolso.

Na sombra: Na sombra profissional, alertam sobre sociedades desiguais, decisões de carreira motivadas por pressão familiar ou social, ou ficar paralisado entre duas oportunidades sem agir.',
  espiritualidade = 'Na luz: Na espiritualidade, Os Enamorados representam a hierogamia — a união sagrada dos opostos dentro de si. É o casamento entre masculino e feminino interior, entre razão e intuição, entre matéria e espírito. Representam a cura pela integração.

Na sombra: Na sombra espiritual, tornam-se a projeção do divino no humano — buscar no outro o que só pode ser encontrado dentro de si, ou confundir dependência emocional com conexão espiritual.',
  voz_do_arcano = 'Nós somos Os Enamorados.
Somos a encruzilhada onde o coração precisa falar.
Em nós, amar é escolher — e escolher é revelar quem você é.
Somos a nudez sem vergonha, a entrega sem garantia.
Na nossa luz, trazemos união, autenticidade e alinhamento.
Na nossa sombra, viramos indecisão, projeção e fuga do compromisso.
Nós não prometemos facilidade.
Prometemos verdade.',
  revisao_rapida = 'Número: VI — harmonia, beleza e responsabilidade
Arquétipo: O Amante, o Escolhedor, a União dos Opostos
Luz: Amor verdadeiro, escolhas alinhadas, autenticidade
Sombra: Indecisão, projeção, fuga do compromisso
Lição: Escolher é revelar quem você é de verdade
Cabala: Zayin (ז) — entre Binah e Tiferet
Anjo: Rafael — ''Deus cura'' — o amor como cura',
  aprofundamento = 'Os Enamorados são o Arcano VI — o número da harmonia, da beleza e da responsabilidade. Se os cinco primeiros arcanos tratam da formação individual (potencial, vontade, intuição, criação, estrutura, tradição), os Enamorados inauguram o encontro com o outro. É o primeiro arcano que não pode existir sozinho — exige relação, espelho, confronto amoroso.',
  cabala = 'Na Cabala, Os Enamorados correspondem à letra Zayin (ז), que significa ''espada''. A espada é o instrumento do discernimento — cortar entre o verdadeiro e o falso, o essencial e o supérfluo. O caminho de Zayin conecta Binah (Entendimento) a Tiferet (Beleza), representando a descida da compreensão para o coração.',
  keywords = ARRAY['Escolha','União','Amor','Valores','Dualidade']::text[],
  status = 'published'::module_status, validated = true,
  updated_at = now()
WHERE type = 'maior' AND number = 6;

UPDATE public.cms_arcanos SET
  essencia = 'O Carro é o Arcano VII — a vontade em movimento, a determinação que vence obstáculos pela força do propósito. Ele não avança pela força bruta, mas pelo domínio de forças opostas que trabalham em uníssono. O guerreiro no carro não luta — ele dirige. Não destrói — ele ultrapassa. Herdeiro do herói triunfal de Roma e do auriga platônico que rege os corcéis da alma, encarna o ego maduro que conquistou autonomia depois de ter sido formado pelo Imperador e abençoado pelos Enamorados. Quando O Carro aparece, o caminho está aberto para quem tem coragem e foco para seguir em frente.',
  simbolos_centrais = 'Duas esfinges (branca e negra): Forças opostas que precisam ser harmonizadas — razão e emoção, consciente e inconsciente

Armadura e estrelas: Proteção espiritual e conexão celestial — o guerreiro guiado pelo alto

Dossel de estrelas: O céu como teto — a jornada é cósmica, não apenas terrena

Cetro curto: Autoridade sobre si mesmo — domínio interno, não externo

Cidade ao fundo: O mundo conhecido que ficou para trás — a zona de conforto superada

Quadrado no peito: Vontade estruturada — a terra (matéria) a serviço do espírito',
  luz = 'Na luz, O Carro é vitória merecida, determinação focada, superação de obstáculos pela força da vontade e progresso rápido. É a energia de quem sabe para onde vai e não se deixa desviar. Aplicado, ele se traduz em metas que avançam mesmo sob pressão, conflitos internos reconciliados em prol de uma direção clara, e a maturidade de conduzir a própria vida sem terceirizar o volante. Quando encontrado na luz, indica que o momento exige ação decisiva, foco absoluto e confiança na própria capacidade de vencer.',
  sombra = 'Na sombra, O Carro se torna agressividade descontrolada, vitória a qualquer custo, obsessão por controle ou avanço sem direção real. É atropelar pessoas no caminho do sucesso, confundir teimosia com determinação, ou correr sem saber para onde. Na sombra, ele pergunta: você está avançando com propósito ou fugindo de algo que ficou para trás?',
  amor = 'Na luz: No amor, O Carro indica conquista ativa, coragem para ir atrás de quem se ama, e relações que avançam com determinação. Pode representar uma fase de progresso no relacionamento, a superação de obstáculos a dois, ou a decisão de lutar pelo amor.

Na sombra: Na sombra amorosa, avisa sobre controle na relação, competição entre parceiros, ou tratar o amor como uma conquista de ego em vez de uma entrega genuína.',
  trabalho = 'Na luz: No trabalho, O Carro fala de promoções, conquistas profissionais, projetos que avançam com velocidade e reconhecimento merecido. É a energia de quem lidera pelo exemplo e supera concorrência com competência.

Na sombra: Na sombra profissional, alerta sobre ambição predatória, burnout por não saber parar, ou atropelar colegas na corrida pelo sucesso.',
  espiritualidade = 'Na luz: Na espiritualidade, O Carro é a disciplina da jornada interior — a capacidade de manter o foco espiritual mesmo em meio ao caos externo. Representa o guerreiro espiritual que domina seus instintos e avança com clareza.

Na sombra: Na sombra espiritual, torna-se ego espiritual — usar o caminho interior como mais uma arena de competição, ou confundir evolução com acumulação de práticas e títulos.',
  voz_do_arcano = 'Eu sou O Carro.
Sou a vontade que se move, a decisão que se torna caminho.
Em mim, forças opostas se alinham sob uma única direção.
Eu sou o guerreiro que não luta — ele conduz.
Na minha luz, eu trago vitória, foco e superação.
Na minha sombra, eu viro obsessão, controle e avanço cego.
Eu não espero permissão.
Eu avanço.',
  revisao_rapida = 'Número: VII — completude dinâmica
Arquétipo: O Guerreiro, o Conquistador, o Condutor
Luz: Determinação, vitória merecida, foco, superação
Sombra: Agressividade, obsessão por controle, avanço cego
Lição: A verdadeira vitória é sobre si mesmo
Cabala: Cheth (ח) — entre Binah e Geburah
Símbolo central: Duas esfinges — forças opostas harmonizadas',
  aprofundamento = 'O Carro é o Arcano VII — o número da completude dinâmica (sete dias, sete notas, sete chakras). Se Os Enamorados inauguram o encontro com o outro, O Carro inaugura o domínio de si. É o primeiro arcano de ação pura após a série contemplativa inicial. Na Jornada do Louco, O Carro representa o momento em que o jovem iniciado sai ao mundo com o que aprendeu.',
  cabala = 'Na Cabala, O Carro corresponde à letra Cheth (ח), que significa ''cerca'' ou ''campo cercado''. A cerca protege o que está dentro — simboliza os limites que preservam a integridade durante o avanço. O caminho de Cheth conecta Binah (Entendimento) a Geburah (Severidade), representando a disciplina que nasce da compreensão profunda.',
  keywords = ARRAY['Determinação','Conquista','Direção','Vitória','Controle']::text[],
  status = 'published'::module_status, validated = true,
  updated_at = now()
WHERE type = 'maior' AND number = 7;

UPDATE public.cms_arcanos SET
  essencia = 'A Justiça é o Arcano VIII — a lei implacável de causa e efeito, o espelho que reflete sem distorção. Ela não julga com emoção; ela mede com precisão. Sentada entre as duas colunas da objetividade, segura a espada da verdade em uma mão e a balança do equilíbrio na outra. Herdeira de Ma''at egípcia, Themis grega e Astreia romana, encarna o princípio cósmico de que toda ação produz reação proporcional, independentemente de quem a pratique. Quando a Justiça aparece, ela diz: o que você plantou, colherá. Não com punição — com exatidão.',
  simbolos_centrais = 'Espada erguida na mão direita: Verdade que corta — discernimento, clareza mental e decisão firme. Erguida na vertical, indica que a verdade não se inclina a um lado: ela permanece reta.

Balança equilibrada na mão esquerda: Equilíbrio, imparcialidade e a pesagem de todas as partes. Está na mão receptiva, lembrando que julgar bem começa por escutar bem.

Coroa com pedra quadrada azul: Pensamento ordenado e julgamento estruturado. O quadrado azul ao centro indica clareza intelectual fundada em princípios estáveis, não em humor.

Manto vermelho: Ação e poder — a justiça não é passiva, ela age. O vermelho lembra que a verdade, quando reconhecida, exige decisão concreta e movimento no mundo.

Véu roxo entre as colunas: A compaixão que sustenta a justiça — sem ela, vira crueldade. O roxo une realeza e espírito: lembra que toda lei serve, no fundo, a um princípio maior.

Duas colunas de pedra: Estrutura e equilíbrio — a lei se sustenta em pilares firmes. As mesmas colunas da Sacerdotisa retornam aqui, agora atravessadas pela consciência que decide entre os opostos.',
  luz = 'Na luz, a Justiça é honestidade radical, responsabilidade pessoal, decisões equilibradas e coragem de encarar a verdade. É o momento de prestar contas com integridade, de assumir as consequências das próprias escolhas e de agir com retidão. Aplicada, ela aparece como acordos justos, contratos honrados, conversas difíceis conduzidas com sobriedade e a paz interna de quem alinhou palavra, pensamento e ação. Quando encontrada na luz, indica que a verdade prevalecerá e que o equilíbrio será restaurado.',
  sombra = 'Na sombra, a Justiça se torna rigidez legalista, frieza desumana, vingança disfarçada de equidade, ou incapacidade de perdoar. É a pessoa que usa ''a verdade'' como arma, que cobra dos outros sem olhar para si, ou que confunde punição com justiça. Na sombra, ela pergunta: você está buscando equilíbrio ou querendo ter razão?',
  amor = 'Na luz: No amor, a Justiça indica relações equilibradas, honestidade mútua, compromissos justos e a capacidade de resolver conflitos com maturidade. Pode representar acordos claros, conversas necessárias, ou o restabelecimento do equilíbrio em uma relação.

Na sombra: Na sombra amorosa, avisa sobre ressentimento acumulado, cobranças desproporcionais, relações onde se ''contabiliza'' cada gesto, ou a frieza de tratar o amor como um contrato.',
  trabalho = 'Na luz: No trabalho, a Justiça fala de contratos justos, negociações equilibradas, decisões éticas e reconhecimento merecido. É a energia de quem age com integridade profissional e colhe os frutos de sua retidão.

Na sombra: Na sombra profissional, alerta sobre disputas legais, injustiças no ambiente de trabalho, decisões antiéticas, ou usar o poder para favorecer interesses próprios às custas de outros.',
  espiritualidade = 'Na luz: Na espiritualidade, a Justiça é a lei do karma — a compreensão de que o universo opera em equilíbrio perfeito. Representa o autoexame honesto, a revisão dos próprios atos e a disposição para ajustar o curso quando necessário.

Na sombra: Na sombra espiritual, torna-se autojulgamento destrutivo, culpa excessiva, ou a crença de que o sofrimento é merecido como ''punição cósmica''. Justiça divina não é vingança.',
  voz_do_arcano = 'Eu sou a Justiça.
Sou o espelho que não mente, a balança que não engana.
A espada que corta na medida exata.
Em mim, toda ação encontra sua consequência.
Na minha luz, eu trago verdade, equilíbrio e responsabilidade.
Na minha sombra, eu viro rigidez, frieza e vingança.
Eu não castigo.
Eu equilibro.',
  revisao_rapida = 'Número: VIII (Rider-Waite) / XI (Marselha)
Arquétipo: A Juíza, a Equilibradora, a Guardiã da Lei Natural
Luz: Honestidade, equilíbrio, responsabilidade, verdade
Sombra: Rigidez, frieza, vingança, autojulgamento
Lição: Responsabilidade é o primeiro passo para a liberdade
Cabala: Lamed (ל) — entre Geburah e Tiferet
Referência mítica: Maat (Egito), Themis (Grécia)',
  aprofundamento = 'A Justiça é o Arcano VIII na tradição Rider-Waite (XI na tradição de Marselha — a troca com A Força é uma das diferenças mais debatidas do Tarô). O número oito é o lemniscata verticalizado — equilíbrio infinito, ciclo perpétuo de causa e efeito. Após a conquista do Carro (VII), a Justiça pede uma pausa para avaliar: a vitória foi justa? O caminho foi íntegro?',
  cabala = 'Na Cabala, a Justiça corresponde à letra Lamed (ל), que significa ''aguilhão'' — o instrumento que guia o boi (a força bruta) na direção certa. É a única letra hebraica que se eleva acima da linha — representando a aspiração ao alto, à retidão. O caminho de Lamed conecta Geburah (Severidade) a Tiferet (Beleza), equilibrando rigor e harmonia.',
  keywords = ARRAY['Equilíbrio','Verdade','Consequência','Responsabilidade','Karma']::text[],
  status = 'published'::module_status, validated = true,
  updated_at = now()
WHERE type = 'maior' AND number = 8;

UPDATE public.cms_arcanos SET
  essencia = 'O Eremita é o Arcano IX — o sábio que se retira do mundo para encontrar a luz que só brilha no silêncio interior. Ele não foge — ele escolhe a solidão como ferramenta de autoconhecimento. No topo da montanha, com sua lanterna e seu bastão, ele ilumina não o mundo, mas o caminho de quem busca com sinceridade. Quando o Eremita aparece, ele convida a parar, olhar para dentro e encontrar suas próprias respostas.',
  simbolos_centrais = 'Lanterna com estrela de seis pontas: A Estrela de Davi / Selo de Salomão — sabedoria que une o acima e o abaixo

Bastão/cajado: Experiência acumulada, autoridade pela vivência, apoio na jornada

Manto cinza com capuz: Discrição, humildade e invisibilidade voluntária — o sábio não busca atenção

Montanha nevada: Conquista espiritual, isolamento elevado e perspectiva ampla

Terreno árido: Desapego material — o Eremita não precisa de nada externo

Postura curvada: Humildade diante do mistério — mesmo o sábio se inclina',
  luz = 'Na luz, o Eremita é sabedoria conquistada pela experiência, introspecção profunda, mentoria silenciosa e a capacidade de estar sozinho sem se sentir solitário. É o professor que ensina pelo exemplo, o terapeuta que escuta sem julgar, o ancião que ilumina sem impor. Aplicado, ele se manifesta como retiros que reorganizam prioridades, estudo aprofundado de um único tema e a economia de palavras de quem só fala quando tem algo verdadeiro a dizer. Quando encontrado na luz, indica que é hora de se recolher, meditar e buscar respostas dentro de si.',
  sombra = 'Na sombra, o Eremita se torna isolamento patológico, misantropia, superioridade espiritual ou recusa do mundo por medo. É quem usa a solidão como muralha, a sabedoria como escudo contra a vulnerabilidade, ou o desapego como desculpa para não se conectar. Na sombra, ele pergunta: você está se recolhendo para crescer ou se escondendo para não sofrer?',
  amor = 'Na luz: No amor, o Eremita indica uma fase de introspecção necessária, um tempo para entender o que realmente se deseja numa relação, ou a presença de alguém sábio e maduro. Pode representar amor que nasce do autoconhecimento e da plenitude, não da carência.

Na sombra: Na sombra amorosa, avisa sobre medo de intimidade, isolamento emocional, dificuldade de se abrir, ou usar a independência como armadura contra a vulnerabilidade do amor.',
  trabalho = 'Na luz: No trabalho, o Eremita fala de pesquisa aprofundada, mentoria, trabalho independente e carreiras que exigem reflexão. É a energia do consultor experiente, do pesquisador, ou de quem precisa de tempo e silêncio para produzir sua melhor obra.

Na sombra: Na sombra profissional, alerta sobre isolamento no trabalho, dificuldade de colaborar em equipe, perfeccionismo que impede a entrega, ou recusar oportunidades por medo de exposição.',
  espiritualidade = 'Na luz: Na espiritualidade, o Eremita é o mestre interior — a conexão com a sabedoria que transcende livros e doutrinas. Representa retiros espirituais, meditação profunda, e a jornada solitária que todo buscador precisa fazer em algum momento.

Na sombra: Na sombra espiritual, torna-se elitismo espiritual, a crença de que a verdade só pertence a poucos, ou o uso da espiritualidade como justificativa para evitar o mundo e suas responsabilidades.',
  voz_do_arcano = 'Eu sou o Eremita.
Sou a luz que brilha no silêncio.
A resposta que nasce da pergunta que ninguém faz em voz alta.
Em mim, a solidão é mestra e o silêncio é linguagem.
Na minha luz, eu trago sabedoria, introspecção e guia interior.
Na minha sombra, eu viro isolamento, frieza e arrogância espiritual.
Eu não busco seguidores.
Eu ilumino quem busca.',
  revisao_rapida = 'Número: IX — completude, 3×3
Arquétipo: O Sábio, o Mentor Interior, o Peregrino da Alma
Luz: Sabedoria, introspecção, mentoria silenciosa
Sombra: Isolamento, misantropia, elitismo espiritual
Lição: As respostas vêm do silêncio interior
Cabala: Yod (י) — entre Chesed e Tiferet
Símbolo central: Lanterna com Estrela de Davi — luz interior',
  aprofundamento = 'O Eremita é o Arcano IX — o número da completude (3x3), do ciclo que se fecha antes de um novo início. Após a sequência de encontros externos (Enamorados, Carro, Justiça), o Eremita marca o retorno ao interior. É a pausa necessária antes da grande virada da Roda da Fortuna (X). Na tradição esotérica, ele é frequentemente associado a Cronos/Saturno — o tempo como mestre.',
  cabala = 'Na Cabala, o Eremita corresponde à letra Yod (י), a menor e mais sagrada das letras hebraicas. Yod é a semente — o ponto primordial de onde toda criação começa. É chamada de ''mão de Deus''. O caminho de Yod conecta Chesed (Misericórdia) a Tiferet (Beleza), representando a compaixão que encontra expressão na harmonia.',
  keywords = ARRAY['Introspecção','Sabedoria','Solidão','Busca Interior','Guia']::text[],
  status = 'published'::module_status, validated = true,
  updated_at = now()
WHERE type = 'maior' AND number = 9;

UPDATE public.cms_arcanos SET
  essencia = 'A Roda da Fortuna é o Arcano X — o ponto de virada, o lembrete cósmico de que tudo gira. O que sobe, desce. O que termina, recomeça. Ela não é controlada por nenhuma figura humana — é a lei dos ciclos operando além da vontade individual. Arquétipo do Destino e do Tempo cíclico, ecoa a Rota Fortunae medieval e a Roda do Samsara oriental: o movimento que nenhum poder humano interrompe e que ensina, em cada giro, a sabedoria do desapego. Quando a Roda aparece, ela diz: algo está mudando, querendo você ou não. A questão não é parar a roda — é como você dança com ela.',
  simbolos_centrais = 'Roda com letras TARO/ROTA: O Tarô como roda eterna — Rota (roda), Taro, Orat (fala), Tora (lei), Ator (ação)

Esfinge no topo: Sabedoria que permanece estável enquanto tudo gira — o ponto fixo

Anúbis ascendendo: A força que sobe — ascensão, nova oportunidade

Tifon descendendo: A força que desce — declínio, fim de ciclo, dissolução

Quatro figuras nos cantos (touro, leão, águia, anjo): Os quatro elementos fixos do zodíaco — estabilidade em meio à mudança

Nuvens: O mistério — a Roda opera em dimensões que transcendem a compreensão humana',
  luz = 'Na luz, a Roda da Fortuna é oportunidade inesperada, mudança favorável, expansão, sorte e o momento certo que chega. É o ciclo ascendente — quando as coisas começam a fluir, portas se abrem e o universo parece conspirar a favor. Aplicada, ela se manifesta como reviravoltas que reposicionam carreira, encontros que reorganizam afetos e a percepção lúcida de que o tempo da espera virou tempo de colheita. Quando encontrada na luz, indica que o vento está a seu favor — aproveite o momento com discernimento, não apenas com euforia.',
  sombra = 'Na sombra, a Roda da Fortuna representa reversão de sorte, instabilidade, sensação de estar à mercê das circunstâncias e a dificuldade de aceitar que nem tudo está sob controle. É o ciclo descendente — quando o que parecia sólido se desestabiliza. Na sombra, ela pergunta: você está resistindo à mudança ou pode aprender a fluir com ela?',
  amor = 'Na luz: No amor, a Roda indica uma nova fase no relacionamento, o encontro com alguém que muda tudo, ou uma virada positiva em uma situação estagnada. Pode representar o destino operando a favor da conexão — o reencontro kármico.

Na sombra: Na sombra amorosa, avisa sobre instabilidade na relação, a sensação de que o relacionamento é uma montanha-russa, ou a dificuldade de sustentar o amor quando as circunstâncias mudam.',
  trabalho = 'Na luz: No trabalho, a Roda fala de oportunidades inesperadas, mudanças de emprego favoráveis, sorte nos negócios e o timing perfeito para um novo projeto. É a energia de estar no lugar certo na hora certa.

Na sombra: Na sombra profissional, alerta sobre instabilidade no emprego, reviravoltas inesperadas nos negócios, ou a sensação de que o controle escapou — é hora de se adaptar, não de resistir.',
  espiritualidade = 'Na luz: Na espiritualidade, a Roda é a lei dos ciclos cósmicos — a compreensão de que reencarnação, karma e evolução operam em espirais ascendentes. Representa a aceitação de que a vida é movimento e que cada fase serve ao crescimento.

Na sombra: Na sombra espiritual, torna-se fatalismo — ''é o destino'' como desculpa para não agir, ou a crença de que estamos absolutamente à mercê de forças externas sem nenhum poder de escolha.',
  voz_do_arcano = 'Eu sou a Roda da Fortuna.
Sou o giro que muda tudo, o ciclo que não para.
A mudança que vem sem pedir licença.
Em mim, o que sobe desce — e o que desce sobe novamente.
Na minha luz, eu trago oportunidade, expansão e sorte.
Na minha sombra, eu trago instabilidade, reversão e impotência.
Não me peça para parar.
Aprenda a dançar enquanto eu giro.',
  revisao_rapida = 'Número: X — ponto médio da jornada
Arquétipo: O Destino, o Ciclo, a Grande Mudança
Luz: Oportunidade, sorte, expansão, timing perfeito
Sombra: Instabilidade, reversão, impotência, fatalismo
Lição: A impermanência é a única constante
Cabala: Kaph (כ) — entre Chesed e Netzach
Símbolo central: Esfinge — estabilidade em meio à mudança',
  aprofundamento = 'A Roda da Fortuna é o Arcano X — o primeiro número de dois dígitos, marcando uma transição. Os nove arcanos anteriores formaram a personalidade; a Roda inaugura uma fase onde forças maiores entram em jogo. É o ponto médio da Jornada do Louco — a metade do caminho entre o início (0) e a completude (XXI). A Roda nos lembra que estamos dentro de algo maior do que nós mesmos.',
  cabala = 'Na Cabala, a Roda da Fortuna corresponde à letra Kaph (כ), que significa ''palma da mão''. A palma é o que segura — e o que solta. É o gesto de dar e receber que mantém o ciclo em movimento. O caminho de Kaph conecta Chesed (Misericórdia) a Netzach (Vitória), representando a generosidade que eventualmente se transforma em conquista.',
  keywords = ARRAY['Ciclos','Destino','Mudança','Sorte','Impermanência']::text[],
  status = 'published'::module_status, validated = true,
  updated_at = now()
WHERE type = 'maior' AND number = 10;

UPDATE public.cms_arcanos SET
  essencia = 'A Força é o Arcano XI — o poder que não precisa gritar para ser ouvido. Não é a força bruta do guerreiro, mas a coragem silenciosa de quem domina seus instintos com compaixão. A mulher que abre a boca do leão não o subjuga — ela o acaricia. É a vitória da consciência sobre o impulso, do amor sobre o medo. Reescritura feminina do herói solar — eco da deusa Cibele com seus leões e da virgem que doma a fera nas alegorias medievais — apresenta o poder espiritual como ternura firme, não como dominação. Quando A Força aparece, ela diz: o verdadeiro poder é gentil.',
  simbolos_centrais = 'Mulher abrindo a boca do leão: Domínio dos instintos pela gentileza — não pela violência. A mão pousa, não esmaga: a fera se rende porque foi reconhecida, não dominada.

Lemniscata (∞) sobre a cabeça: Consciência infinita — o mesmo símbolo do Mago, agora internalizado. Indica que o poder espiritual aqui já não está nas mãos: está na própria mente serena.

Guirlanda de flores na cintura e cabeça: A beleza que domestica a fera — o poder do feminino que liga e suaviza. Une a figura ao leão como um cinturão vivo: a coragem se enfeita, não se arma.

Leão dourado submetido: Os instintos, as paixões, a natureza animal que precisa ser integrada. Sua cor solar revela que esses impulsos não são inimigos — são energia bruta a ser canalizada.

Manto branco esvoaçante: Pureza de intenção — a força a serviço do bem. O branco indica que esta dominação é interior: nada precisa ser provado para fora.

Paisagem verde e serena: Harmonia interior — o ambiente reflete o estado interno. A natureza calma confirma: quando a fera dentro foi reconciliada, o mundo ao redor para de rugir.',
  luz = 'Na luz, A Força é coragem compassiva, autodomínio, paciência infinita e a capacidade de enfrentar o medo sem se tornar violenta. É a mãe que acalma a criança em pânico, a mulher que enfrenta uma situação aterrorizante com serenidade, a líder que inspira sem intimidar. Aplicada, ela aparece como impulsos domados sem repressão, conversas tensas conduzidas com firmeza afetuosa e a autoestima quieta de quem não precisa provar nada para sustentar sua presença. Quando encontrada na luz, indica que você tem mais força do que imagina — e ela está na sua suavidade.',
  sombra = 'Na sombra, A Força se torna repressão emocional, controle excessivo dos instintos, passividade disfarçada de paciência, ou explosões quando a contenção se rompe. É negar a raiva, sufocar o desejo, ou se convencer de que ''ser forte'' é nunca sentir. Na sombra, ela pergunta: você está integrando seus instintos ou apenas os amordaçando?',
  amor = 'Na luz: No amor, A Força indica paixão equilibrada, coragem para amar com vulnerabilidade, paciência com o processo do outro e a capacidade de sustentar o amor mesmo nas dificuldades. É o amor que não desiste no primeiro conflito.

Na sombra: Na sombra amorosa, avisa sobre repressão de desejos, relações onde um ''engole'' tudo para manter a paz, ou explosões emocionais acumuladas que destroem o que foi construído.',
  trabalho = 'Na luz: No trabalho, A Força fala de persistência, resiliência, liderança compassiva e a capacidade de enfrentar desafios com calma e determinação. É a energia de quem sustenta projetos longos com paciência.

Na sombra: Na sombra profissional, alerta sobre esgotamento por não estabelecer limites, suportar situações abusivas em nome da ''fortaleza'', ou reprimir frustrações que explodem em momentos inoportunos.',
  espiritualidade = 'Na luz: Na espiritualidade, A Força é a alquimia interior — transformar instintos brutos em sabedoria encarnada. Representa a prática da não-violência (ahimsa), a integração da sombra junguiana, e a compreensão de que o sagrado habita também o animal.

Na sombra: Na sombra espiritual, torna-se bypass espiritual — usar a ''elevação'' como desculpa para negar raiva, sexualidade ou outras forças vitais legítimas.',
  voz_do_arcano = 'Eu sou A Força.
Sou a mão que acaricia a fera, a coragem que não precisa gritar.
Em mim, o poder encontra a gentileza e o instinto encontra a consciência.
Eu sou a paciência que não se esgota, o amor que não recua.
Na minha luz, eu trago coragem, compaixão e domínio interior.
Na minha sombra, eu viro repressão, rigidez e negação do instinto.
Eu não domino pela violência.
Eu abraço.',
  revisao_rapida = 'Número: XI (Rider-Waite) / VIII (Marselha)
Arquétipo: A Domadora, a Guerreira Gentil
Luz: Coragem compassiva, paciência, autodomínio
Sombra: Repressão emocional, bypass espiritual, rigidez
Lição: Verdadeira coragem é agir com amor apesar do medo
Cabala: Teth (ט) — entre Chesed e Geburah
Signo: Leão — força vital, coragem, coração',
  aprofundamento = 'A Força é o Arcano XI na tradição Rider-Waite (VIII na tradição de Marselha). A troca com a Justiça foi feita por Arthur Edward Waite para alinhar com correspondências astrológicas (Leão = Força). O número 11 é um número mestre — duplicação do 1, indicando poder amplificado pela consciência. Após a Roda da Fortuna mostrar que forças externas operam, A Força revela o poder interno que nenhuma roda pode tirar.',
  cabala = 'Na Cabala, A Força corresponde à letra Teth (ט), que significa ''serpente''. A serpente é a kundalini — a energia vital enrolada na base da coluna que, quando desperta conscientemente, ilumina. O caminho de Teth conecta Chesed (Misericórdia) a Geburah (Severidade), representando a força que nasce da compaixão e se aplica com rigor amoroso.',
  keywords = ARRAY['Coragem','Compaixão','Domínio Interior','Paciência','Poder Suave']::text[],
  status = 'published'::module_status, validated = true,
  updated_at = now()
WHERE type = 'maior' AND number = 11;

UPDATE public.cms_arcanos SET
  essencia = 'O Enforcado é o Arcano XII — a pausa radical, a inversão de perspectiva que só acontece quando paramos de lutar. Ele não está preso — está suspenso por escolha própria. Pendurado de cabeça para baixo, vê o mundo de um ângulo que ninguém mais vê. Seu rosto é sereno, não atormentado. Arquétipo do Sacrifício iniciático — irmão de Odin pendurado em Yggdrasil em busca das runas — encarna a sabedoria que só se conquista quando o ego aceita ficar de cabeça para baixo. Quando O Enforcado aparece, ele diz: pare de forçar. A resposta vem quando você solta.',
  simbolos_centrais = 'Homem pendurado pelo pé direito: Inversão voluntária — ver o mundo de uma perspectiva completamente nova. Não é castigo: ele se entregou à corda para enxergar o que de pé não conseguia.

Perna esquerda cruzada formando um 4: Estabilidade na entrega — posição de meditação invertida. O 4 desenhado pelas pernas indica ordem oculta: mesmo de cabeça para baixo, há estrutura interior.

Auréola dourada ao redor da cabeça: Iluminação pela rendição — a sabedoria que nasce da pausa. O ouro irradia da mente que parou de lutar, mostrando que a luz vem por dentro, não por feito.

Árvore viva em forma de T (Tau): A árvore da vida e a cruz Tau hebraica — o sacrifício que gera crescimento. Está coberta de folhas: o suporte que o sustenta continua vivo, não é instrumento de morte.

Rosto sereno e olhos abertos: Aceitação pacífica — não há sofrimento, há compreensão. O olhar consciente revela que ele escolhe estar ali: a iniciação só funciona quando consentida.

Mãos cruzadas atrás das costas: Soltar o controle — não agir é, às vezes, a ação mais sábia. As mãos invisíveis mostram que o poder, neste momento, está em conter o gesto.',
  luz = 'Na luz, O Enforcado é sabedoria pela pausa, perspectiva renovada, desapego consciente e a coragem de não agir quando tudo pede ação. É o momento de suspender o julgamento, soltar o controle e permitir que a vida revele seu próprio caminho. Aplicado, ele se traduz em sabáticos restauradores, mudanças de ângulo que dissolvem impasses antigos e a entrega lúcida de quem percebe que render-se também é uma forma de avançar. Quando encontrado na luz, indica que a resposta virá — mas só se você parar de buscá-la freneticamente.',
  sombra = 'Na sombra, O Enforcado se torna estagnação disfarçada de paciência, martírio, vitimismo, ou a recusa de agir por medo das consequências. É quem se sacrifica para ganhar pena, quem espera eternamente sem nunca decidir, ou quem usa a ''entrega espiritual'' para evitar responsabilidade. Na sombra, ele pergunta: você está se rendendo ou se sabotando?',
  amor = 'Na luz: No amor, O Enforcado indica uma pausa necessária para ver a relação sob nova perspectiva, sacrifício saudável pelo bem do casal, ou o momento de soltar expectativas e aceitar o outro como ele é.

Na sombra: Na sombra amorosa, avisa sobre relações onde um se sacrifica demais, martírio afetivo, ficar preso em situações amorosas por medo de mudança, ou usar a ''entrega'' como manipulação.',
  trabalho = 'Na luz: No trabalho, O Enforcado fala de pausas criativas, mudança de estratégia, projetos que precisam de tempo para amadurecer e a sabedoria de esperar o momento certo em vez de forçar resultados.

Na sombra: Na sombra profissional, alerta sobre procrastinação, projetos paralisados indefinidamente, ou aceitar condições injustas em nome de uma ''rendição'' que é, na verdade, submissão.',
  espiritualidade = 'Na luz: Na espiritualidade, O Enforcado é a rendição ao mistério — a aceitação de que nem tudo pode ser compreendido pela mente racional. Representa práticas contemplativas, retiros de silêncio, e a experiência mística de dissolução do ego.

Na sombra: Na sombra espiritual, torna-se passividade total, a crença de que ''o universo resolverá tudo'' sem nenhum esforço pessoal, ou usar o sofrimento como moeda espiritual.',
  voz_do_arcano = 'Eu sou O Enforcado.
Sou a pausa que revela, a inversão que ilumina.
Em mim, soltar é ganhar e esperar é agir.
Eu vejo o mundo de cabeça para baixo — e por isso vejo o que outros não veem.
Na minha luz, eu trago perspectiva, rendição e sabedoria pela pausa.
Na minha sombra, eu viro estagnação, martírio e vitimismo.
Eu não estou preso.
Eu escolhi ficar.',
  revisao_rapida = 'Número: XII — ciclo completo, transição
Arquétipo: O Suspenso, o Místico, o Sacrificante Voluntário
Luz: Rendição sábia, perspectiva nova, desapego
Sombra: Estagnação, martírio, vitimismo, passividade
Lição: Rendição não é derrota — soltar é ganhar
Cabala: Mem (מ) — entre Geburah e Hod
Mito: Odin na árvore Yggdrasil — sabedoria pelo sacrifício',
  aprofundamento = 'O Enforcado é o Arcano XII — o número do ciclo completo (12 meses, 12 signos, 12 apóstolos). Após a sequência de poder e conquista (Força, Justiça, Carro), O Enforcado introduz um conceito radical: às vezes, o maior poder é a imobilidade. Na Jornada do Louco, ele marca a transição entre a primeira metade (construção do ego) e a segunda (dissolução e transformação).',
  cabala = 'Na Cabala, O Enforcado corresponde à letra Mem (מ), que significa ''água''. A água é o elemento da rendição — assume a forma do recipiente, flui para o ponto mais baixo, mas é a força mais poderosa da natureza. O caminho de Mem conecta Geburah (Severidade) a Hod (Esplendor), representando a disciplina que se transforma em humildade radiante.',
  keywords = ARRAY['Rendição','Suspensão','Sacrifício','Perspectiva','Entrega']::text[],
  status = 'published'::module_status, validated = true,
  updated_at = now()
WHERE type = 'maior' AND number = 12;

UPDATE public.cms_arcanos SET
  essencia = 'A Morte é o Arcano XIII — a transformação inevitável, o fim que é também começo. Ela não é destruição: é a foice que ceifa o que já cumpriu seu propósito para que algo novo possa nascer. O cavaleiro esquelético não faz distinção — passa por reis, bispos, crianças e donzelas igualmente. Encarnação do princípio alquímico do nigredo — a putrefação que precede toda transmutação — é também o Ceifeiro arquetípico que aparece de Saturno a Yama, lembrando que nenhuma forma viva atravessa o tempo sem se desfazer. Quando A Morte aparece, ela diz: algo precisa terminar para que você possa seguir. Não resista.',
  simbolos_centrais = 'Cavaleiro esquelético em armadura negra: A morte como força invencível e imparcial — não pode ser comprada ou evitada

Cavalo branco: Pureza da transformação — a mudança em si é neutra, não boa ou má

Bandeira com rosa mística (cinco pétalas): A rosa de cinco pétalas — a vida que persiste além da morte, os cinco sentidos renascidos

Sol nascente entre duas torres: A promessa do renascimento — o sol que nasce após a noite mais escura

Rio fluindo ao fundo: O fluxo constante da vida — a água que nunca para

Figuras caídas e ajoelhadas: Diferentes reações à mudança — resistência, medo, aceitação, oração',
  luz = 'Na luz, A Morte é libertação do que não serve mais, transformação profunda, desapego necessário e renascimento. É o divórcio que liberta, a mudança de carreira que aterroriza mas salva, o luto que abre espaço para nova vida. Aplicada, ela aparece como a clareza para encerrar ciclos sem culpa, a leveza de quem solta papéis antigos e a coragem de habitar uma identidade que ainda está se formando. Quando encontrada na luz, indica que o fim que você teme é, na verdade, a porta para o que mais deseja.',
  sombra = 'Na sombra, A Morte se torna resistência desesperada à mudança, apego ao que já morreu, medo paralisante do fim, ou destruição sem propósito. É se agarrar a um relacionamento morto, a um emprego que esgota, a uma versão de si mesma que já não existe. Na sombra, ela pergunta: o que você está mantendo vivo artificialmente?',
  amor = 'Na luz: No amor, A Morte indica o fim de um padrão que bloqueava o amor verdadeiro, a transformação profunda de uma relação, ou o encerramento de um ciclo que abre espaço para algo mais autêntico.

Na sombra: Na sombra amorosa, avisa sobre o fim doloroso de uma relação, a recusa de aceitar que o amor acabou, ou a destruição de vínculos por medo de intimidade.',
  trabalho = 'Na luz: No trabalho, A Morte fala de reestruturações necessárias, fim de projetos que abrem espaço para novos, mudanças radicais de carreira que levam ao crescimento, e a coragem de encerrar o que não funciona mais.

Na sombra: Na sombra profissional, alerta sobre demissões inesperadas, fim de empresas ou parcerias, ou a recusa de se adaptar a mudanças inevitáveis no mercado.',
  espiritualidade = 'Na luz: Na espiritualidade, A Morte é a iniciação suprema — a morte do ego, o renascimento da consciência. Representa a experiência mística de dissolução, a compreensão de que somos mais do que nosso corpo e nossa história, e a aceitação da impermanência como caminho de libertação.

Na sombra: Na sombra espiritual, torna-se obsessão com o fim, niilismo espiritual, ou a crença de que destruir é mais sagrado do que construir.',
  voz_do_arcano = 'Eu sou A Morte.
Sou o fim que é começo, a foice que abre caminho.
Em mim, o que morreu dá lugar ao que nasce.
Eu passo por reis e mendigos igualmente — a transformação não faz distinção.
Na minha luz, eu trago libertação, renascimento e desapego.
Na minha sombra, eu viro resistência, apego e medo paralisante.
Eu não destruo.
Eu transformo.',
  revisao_rapida = 'Número: XIII — transformação radical
Arquétipo: A Ceifadora, a Transformadora, a Grande Passagem
Luz: Libertação, renascimento, desapego necessário
Sombra: Resistência à mudança, apego, medo paralisante
Lição: Todo fim contém uma semente de começo
Cabala: Nun (נ) — entre Tiferet e Netzach
Símbolo central: Rosa mística — a vida além da morte',
  aprofundamento = 'A Morte é o Arcano XIII — o número mais temido e mais incompreendido. Na numerologia, 13 é o número da transformação radical (12 + 1 = ciclo completo + novo início). Na sequência dos arcanos, A Morte vem após O Enforcado (rendição): primeiro nos rendemos, depois somos transformados. É a conclusão lógica — quem se entrega à mudança, morre para o velho e renasce.',
  cabala = 'Na Cabala, A Morte corresponde à letra Nun (נ), que significa ''peixe''. O peixe vive nas profundezas invisíveis — simboliza o que existe abaixo da superfície da consciência. O caminho de Nun conecta Tiferet (Beleza) a Netzach (Vitória), representando a transformação da harmonia pessoal em triunfo espiritual — mas apenas através da dissolução.',
  keywords = ARRAY['Transformação','Fim','Renascimento','Liberação','Ciclo']::text[],
  status = 'published'::module_status, validated = true,
  updated_at = now()
WHERE type = 'maior' AND number = 13;

UPDATE public.cms_arcanos SET
  essencia = 'A Temperança é o Arcano XIV — a arte sagrada de misturar, equilibrar e integrar. Após a destruição radical d''A Morte, a Temperança chega como a cura — o processo lento e alquímico de reconstruir com harmonia. O anjo que despeja água entre dois cálices não mistura ao acaso: ele dosa com precisão, encontrando a proporção exata entre os opostos. Quando A Temperança aparece, ela diz: não é hora de extremos — é hora de encontrar o meio.',
  simbolos_centrais = 'Anjo com asas de fogo: Ser intermediário entre o divino e o humano — mensageiro celestial

Dois cálices com água fluindo: A mistura alquímica dos opostos — consciente e inconsciente, matéria e espírito

Um pé na água, outro na terra: Equilíbrio entre emoção e matéria — entre sentir e agir

Triângulo dentro de um quadrado no peito: Espírito (triângulo) integrado na matéria (quadrado) — a alquimia completa

Caminho dourado ao fundo: O caminho do meio — a via que leva à iluminação

Sol/coroa dourada no horizonte: A meta final — a integração total que ainda está por vir',
  luz = 'Na luz, A Temperança é paciência alquímica, integração dos opostos, cura gradual e o talento de encontrar equilíbrio em situações complexas. É a terapeuta que sabe dosar intervenção e escuta, a artista que mistura cores até encontrar o tom exato, a pessoa que navega conflitos sem perder o centro. Aplicada, ela aparece como dietas e ritmos sustentáveis, finanças equilibradas a longo prazo e relações onde dar e receber circulam com naturalidade. Quando encontrada na luz, indica que a moderação é o caminho — e que o tempo, bem dosado, é o melhor solvente.',
  sombra = 'Na sombra, A Temperança se torna indecisão crônica disfarçada de equilíbrio, mediocridade por medo de extremos, passividade, ou a incapacidade de se posicionar. É diluir tanto as tintas que nenhuma cor aparece, evitar conflitos a todo custo, ou perder a identidade na tentativa de agradar todos os lados. Na sombra, ela pergunta: você está equilibrando ou se anulando?',
  amor = 'Na luz: No amor, A Temperança indica harmonia no relacionamento, equilíbrio entre dar e receber, cura de feridas passadas e a capacidade de integrar diferenças complementares. Pode representar uma relação que cura, uma reconciliação saudável, ou o amor como alquimia.

Na sombra: Na sombra amorosa, avisa sobre relações mornas por medo de conflito, anular-se para manter a harmonia, ou evitar conversas difíceis em nome da ''paz''.',
  trabalho = 'Na luz: No trabalho, A Temperança fala de colaboração harmoniosa, projetos que exigem paciência e refinamento, gestão equilibrada de recursos e a sabedoria de não forçar resultados prematuros.

Na sombra: Na sombra profissional, alerta sobre falta de ambição disfarçada de contentamento, projetos que nunca saem da fase de ''ajustes'', ou mediocridade por evitar riscos.',
  espiritualidade = 'Na luz: Na espiritualidade, A Temperança é o caminho do meio — a via budista, o equilíbrio entre ascetismo e indulgência, a integração de corpo e espírito. Representa a cura holística, a prática equilibrada e a compreensão de que o sagrado está na proporção, não no excesso.

Na sombra: Na sombra espiritual, torna-se relativismo total — ''tudo é válido'', sem discernimento. Ou a recusa de mergulhar profundamente por medo de perder o equilíbrio.',
  voz_do_arcano = 'Eu sou A Temperança.
Sou a mão que mistura, o fogo que purifica, a água que cura.
Em mim, os opostos se encontram e se transformam em algo novo.
Eu sou o caminho do meio, a paciência que alquimiza.
Na minha luz, eu trago equilíbrio, cura e integração.
Na minha sombra, eu viro indecisão, mediocridade e anulação.
Eu não forço.
Eu doso.',
  revisao_rapida = 'Número: XIV — mediação, cura, alquimia
Arquétipo: O Alquimista, o Curador, o Anjo da Medida
Luz: Equilíbrio, integração, paciência, cura gradual
Sombra: Indecisão, mediocridade, anulação de si
Lição: O caminho do meio não é mediocridade — é maestria
Cabala: Samekh (ס) — entre Tiferet e Yesod
Virtude grega: Sophrosyne — a moderação como base da sabedoria',
  aprofundamento = 'A Temperança é o Arcano XIV — 1+4 = 5, o número da humanidade e da mediação. Após a destruição radical d''A Morte (XIII), A Temperança é o processo de cura e reconstrução. É a alquimia em sua essência: não se trata de destruir os opostos, mas de integrá-los em uma nova substância, superior a ambos. Na tradição esotérica, é frequentemente associada ao signo de Sagitário — o arqueiro que mira no alto enquanto galopa pela terra.',
  cabala = 'Na Cabala, A Temperança corresponde à letra Samekh (ס), que significa ''esteio'' ou ''suporte''. É a estrutura que sustenta sem aprisionar — o andaime que permite a construção. O caminho de Samekh conecta Tiferet (Beleza) a Yesod (Fundamento), representando a descida harmoniosa da consciência elevada para a experiência concreta.',
  keywords = ARRAY['Equilíbrio','Integração','Paciência','Alquimia','Harmonia']::text[],
  status = 'published'::module_status, validated = true,
  updated_at = now()
WHERE type = 'maior' AND number = 14;

UPDATE public.cms_arcanos SET
  essencia = 'O Diabo é o Arcano XV — o espelho sombrio que revela as correntes que vestimos por escolha. Ele não é o mal absoluto: é a ilusão de que estamos presos quando, na verdade, as correntes estão frouxas. A figura demoníaca entronizada não aprisiona — ele seduz. Os dois amantes acorrentados a seus pés poderiam se libertar a qualquer momento, mas não o fazem. Quando O Diabo aparece, ele pergunta: do que você é escrava sem perceber?',
  simbolos_centrais = 'Figura demoníaca com chifres de bode: Pan/Baphomet — os instintos, a matéria, a força vital bruta

Tocha invertida na mão: Luz às avessas — conhecimento usado para escravizar em vez de libertar

Pentáculo invertido na testa: Matéria dominando o espírito — inversão dos valores naturais

Dois amantes acorrentados: Ecos dos Enamorados (VI) — o amor livre agora preso por apegos

Correntes frouxas: A ilusão da prisão — poderiam se libertar, mas escolhem ficar

Pedestal negro: A matéria densa, a ignorância, o trono do ego',
  luz = 'Na luz, O Diabo é a confrontação honesta com a própria sombra, a compreensão dos próprios vícios e padrões, e a energia vital crua que, quando canalizada, se torna força criativa. É o humor negro que desmascara hipocrisias, a sexualidade vivida sem culpa, e a ambição que impulsiona sem escravizar. Quando encontrado na luz, indica que é hora de olhar de frente para o que você evita ver.',
  sombra = 'Na sombra, O Diabo se torna dependência — emocional, química, material ou comportamental. É o vício que nega ser vício, a relação tóxica que se chama de amor, o consumismo que se finge de conquista. É a voz que diz ''só mais uma vez'', ''preciso disso para ser feliz'', ''não consigo viver sem''. Na sombra, ele não pergunta — ele sussurra o que você quer ouvir.',
  amor = 'Na luz: No amor, O Diabo indica paixão intensa, atração magnética, sexualidade poderosa e a honestidade de reconhecer os próprios desejos sem julgamento. Pode representar uma relação que expõe sombras para curar.

Na sombra: Na sombra amorosa, avisa sobre relações tóxicas, codependência, ciúmes obsessivos, manipulação sexual, ou confundir intensidade com profundidade.',
  trabalho = 'Na luz: No trabalho, O Diabo fala de ambição saudável, compreensão das dinâmicas de poder, e a capacidade de negociar com astúcia sem perder a integridade.

Na sombra: Na sombra profissional, alerta sobre ganância, exploração, workaholia, corrupção, ou vender a alma por dinheiro e status.',
  espiritualidade = 'Na luz: Na espiritualidade, O Diabo é o guardião do limiar — a sombra que precisa ser enfrentada para avançar. Representa o trabalho com a sombra junguiana, a descida ao submundo (como Inanna), e a compreensão de que a luz precisa conhecer a escuridão.

Na sombra: Na sombra espiritual, torna-se magia negra, manipulação energética, cultos que usam espiritualidade para controlar, ou negar a existência da sombra por ''ser evoluído demais''.',
  voz_do_arcano = 'Eu sou O Diabo.
Sou o espelho que você evita, a corrente que você não percebe.
A verdade que você prefere não ver.
Em mim mora tudo o que você nega.
Na minha luz, eu trago confrontação, honestidade e força vital.
Na minha sombra, eu viro dependência, ilusão e escravidão voluntária.
As correntes estão frouxas.
Você pode tirá-las quando quiser.',
  revisao_rapida = 'Número: XV — reflexo sombrio dos Enamorados (VI)
Arquétipo: O Tentador, o Senhor das Ilusões
Luz: Confrontação com a sombra, força vital, honestidade
Sombra: Dependência, ilusão, escravidão voluntária
Lição: As correntes estão frouxas — a liberdade é sua escolha
Cabala: Ayin (ע) — entre Tiferet e Hod
Referência: Pan, Baphomet — instinto e matéria como forças sagradas',
  aprofundamento = 'O Diabo é o Arcano XV — 1+5 = 6, o número dos Enamorados. Não é coincidência: O Diabo é o reflexo sombrio dos Enamorados. Onde no VI havia escolha livre e nudez inocente, no XV há correntes e nudez aprisionada. A mesma energia do amor, quando distorcida pelo apego, se transforma em prisão. Na Jornada do Louco, O Diabo é o confronto inevitável com a própria sombra — sem ele, não há iluminação autêntica.',
  cabala = 'Na Cabala, O Diabo corresponde à letra Ayin (ע), que significa ''olho''. O olho é a percepção — e O Diabo distorce a percepção, fazendo ver prisão onde há liberdade, necessidade onde há desejo, destino onde há escolha. O caminho de Ayin conecta Tiferet (Beleza) a Hod (Esplendor), representando a distorção que ocorre quando a beleza se torna vaidade e o esplendor se torna exibicionismo.',
  keywords = ARRAY['Ilusão','Apego','Sombra','Dependência','Materialismo']::text[],
  status = 'published'::module_status, validated = true,
  updated_at = now()
WHERE type = 'maior' AND number = 15;

UPDATE public.cms_arcanos SET
  essencia = 'A Torre é o Arcano XVI — o raio que destrói o que foi construído sobre fundamentos falsos. Não é punição divina: é revelação súbita. A estrutura que desmorona não era sólida — era ilusão de segurança. As figuras que caem não estão morrendo — estão sendo libertadas à força do que as aprisionava. Eco da Torre de Babel e do mito prometeico do fogo roubado, é o arquétipo da revelação cataclísmica: o instante em que o céu intervém para impedir que o ego construa mais alto do que sua própria verdade suporta. Quando A Torre aparece, ela diz: o que não pode se sustentar na verdade, cairá.',
  simbolos_centrais = 'Torre erguida sobre rocha solitária: Estrutura do ego ou falsa segurança destruída pela verdade divina. Construída no alto e isolada, simboliza tudo o que se elevou sem alicerce verdadeiro — orgulho, ilusão, dogma.

Raio que desce do céu: Revelação súbita — a verdade que não pode ser ignorada. Vem de cima, não de dentro: a Torre é abalada por uma intervenção maior do que a vontade humana.

Coroa dourada caindo: Queda do ego, da falsa autoridade, das ilusões de grandeza. O símbolo do poder mundano se desprende primeiro — aviso de que tudo que coroava o falso será derrubado também.

Duas figuras lançadas no vazio: Libertação forçada — o colapso como passagem, não como fim. Caem de cabeça para baixo como o Enforcado, mas sem escolha: a vida inverte por elas o que elas não souberam inverter por dentro.

Chamas saindo das janelas: Purificação pelo fogo — o que era falso queima. As três aberturas em chamas evocam a tríade mente, coração e instinto sendo simultaneamente atingidos pela revelação.

Vinte e duas chamas yod ao redor: Os 22 caminhos da Árvore da Vida descendo como faíscas divinas. Lembram que a destruição não é cega: é a própria centelha sagrada reordenando o que se desviou do real.',
  luz = 'Na luz, A Torre é libertação súbita, revelação transformadora, colapso que abre espaço para o autêntico e a coragem de reconstruir do zero. É o diagnóstico que salva a vida, a traição que revela a verdade, o terremoto que destrói a casa velha e permite construir uma nova. Aplicada, ela aparece como ilusões que finalmente caem, estruturas falsas dissolvidas a tempo e a clareza brutal — e libertadora — de quem prefere a verdade nua à segurança fingida. Quando encontrada na luz, indica que a destruição que você teme é, na verdade, a libertação que precisa.',
  sombra = 'Na sombra, A Torre se torna destruição sem propósito, caos, trauma não processado, ou a tendência de sabotar tudo antes que desmorone sozinho. É destruir relações por medo de ser abandonada, provocar crises para se sentir viva, ou negar a reconstrução por estar viciada no drama. Na sombra, ela pergunta: você está sendo libertada ou está se destruindo?',
  amor = 'Na luz: No amor, A Torre indica revelações que transformam a relação, a queda de máscaras que permite intimidade verdadeira, ou o fim súbito de uma ilusão que abre espaço para amor autêntico.

Na sombra: Na sombra amorosa, avisa sobre separações traumáticas, traições reveladas, relações que desmoronam quando a verdade vem à tona, ou destruição impulsiva de vínculos por medo.',
  trabalho = 'Na luz: No trabalho, A Torre fala de reestruturações radicais que eram necessárias, mudanças súbitas que abrem novos caminhos, e a coragem de abandonar projetos falidos para recomeçar com autenticidade.

Na sombra: Na sombra profissional, alerta sobre demissões inesperadas, falências, colapso de empresas, ou ambientes de trabalho tóxicos que explodem em crise.',
  espiritualidade = 'Na luz: Na espiritualidade, A Torre é o despertar abrupto — o momento em que todas as ilusões se dissolvem de uma vez. Representa a ''noite escura da alma'' de São João da Cruz, a desconstrução necessária das crenças limitantes e o colapso do ego espiritual.

Na sombra: Na sombra espiritual, torna-se crise existencial sem resolução, perda total de fé, ou destruição nihilista de toda estrutura de significado.',
  voz_do_arcano = 'Eu sou A Torre.
Sou o raio que revela, o colapso que liberta.
Em mim, o que é falso não sobrevive.
E o que é verdadeiro emerge dos escombros.
Na minha luz, eu trago revelação, libertação e recomeço.
Na minha sombra, eu viro destruição, caos e trauma.
Eu não peço permissão.
Eu destruo para libertar.',
  revisao_rapida = 'Número: XVI — colapso revelador
Arquétipo: O Relâmpago, o Destruidor Sagrado
Luz: Revelação, libertação súbita, recomeço
Sombra: Destruição sem propósito, caos, trauma
Lição: O que é falso cairá — recomeçar é coragem
Cabala: Pe (פ) — entre Netzach e Hod
Referência: Torre de Babel — arrogância destronada',
  aprofundamento = 'A Torre é o Arcano XVI — 1+6 = 7, o número do Carro. Onde o Carro avança por vontade, A Torre desmorona por verdade. É o contraponto kármico: o que foi construído pela força do ego será testado pela força do real. Na Jornada do Louco, A Torre vem após O Diabo (XV): as correntes da ilusão são rompidas — não suavemente, mas pela força do raio.',
  cabala = 'Na Cabala, A Torre corresponde à letra Pe (פ), que significa ''boca''. A boca é o órgão da palavra — e A Torre é a palavra de verdade que, quando finalmente pronunciada, destrói o silêncio cúmplice. O caminho de Pe conecta Netzach (Vitória) a Hod (Esplendor), representando a destruição da falsa vitória e do falso esplendor.',
  keywords = ARRAY['Destruição','Revelação','Colapso','Libertação','Verdade']::text[],
  status = 'published'::module_status, validated = true,
  updated_at = now()
WHERE type = 'maior' AND number = 16;

UPDATE public.cms_arcanos SET
  essencia = 'A Estrela é o Arcano XVII — a cura que vem após a destruição, a esperança que brilha após a noite mais escura. Após o colapso d''A Torre, A Estrela chega como um bálsamo: nua, vulnerável, serena, despejando água na terra e no rio. Ela não promete que o sofrimento acabou — promete que há sentido nele. Reflexo da deusa Ísis derramando as águas do Nilo e da Estrela Polar que orienta os navegantes na escuridão, é o arquétipo da fé reencontrada — não cega, mas reconciliada com a vida. Quando A Estrela aparece, ela diz: respire. Há luz depois da tempestade.',
  simbolos_centrais = 'Mulher nua à beira d''água: Vulnerabilidade sem vergonha — a alma exposta após a purificação

Estrela grande de oito pontas: Vênus/Ishtar — a estrela da manhã, esperança e renascimento

Sete estrelas menores: Os sete chakras, os sete planetas clássicos — harmonia cósmica

Dois cântaros de água: Um na terra (matéria), outro no rio (emoções) — nutrir ambos os mundos

Pássaro na árvore: Íbis sagrado de Thoth — a sabedoria que retorna após a destruição

Paisagem verde e aberta: Renovação — a vida que renasce após o colapso',
  luz = 'Na luz, A Estrela é esperança genuína, inspiração criativa, cura profunda e a serenidade de quem passou pela tempestade e encontrou terra firme. É a artista que cria a partir da dor, a sobrevivente que transforma trauma em sabedoria, a alma que brilha mais forte por ter sido quebrada. Aplicada, ela se manifesta como rotinas de cuidado que se tornam ritual, fé reconstruída sem ingenuidade e a doçura rara de quem volta a confiar na vida com olhos abertos. Quando encontrada na luz, indica que a cura está acontecendo — confie.',
  sombra = 'Na sombra, A Estrela se torna desesperança disfarçada de resignação, esperança passiva sem ação, desconexão da realidade, ou vulnerabilidade que se torna fragilidade crônica. É esperar que o universo resolva sem fazer sua parte, ou se expor demais sem proteger o que é sagrado. Na sombra, ela pergunta: sua esperança é ativa ou é apenas desejo de que a dor passe?',
  amor = 'Na luz: No amor, A Estrela indica cura emocional, renovação da fé no amor, conexão baseada em vulnerabilidade autêntica e relações que inspiram. Pode representar um amor que chega após um período de dor, ou a reconciliação consigo mesma.

Na sombra: Na sombra amorosa, avisa sobre idealização excessiva do amor, esperar passivamente pelo parceiro ideal, ou se expor emocionalmente sem critério por medo de fechar o coração.',
  trabalho = 'Na luz: No trabalho, A Estrela fala de inspiração renovada, projetos criativos que nascem da autenticidade, reconhecimento merecido e vocação reencontrada. É a energia de quem finalmente encontra seu propósito.

Na sombra: Na sombra profissional, alerta sobre devaneios sem execução, projetos inspirados mas sem estrutura, ou esperar ser ''descoberta'' sem fazer o trabalho necessário.',
  espiritualidade = 'Na luz: Na espiritualidade, A Estrela é a conexão direta com o divino — sem intermediários, sem dogmas, sem rituais elaborados. Representa a meditação sob o céu aberto, a cura energética, e a compreensão de que somos feitas da mesma matéria das estrelas.

Na sombra: Na sombra espiritual, torna-se new age superficial, espiritualidade que nega a dor, ou a crença de que ''pensamento positivo'' substitui trabalho interior real.',
  voz_do_arcano = 'Eu sou A Estrela.
Sou a luz que brilha depois da tempestade.
A esperança que renasce dos escombros.
Em mim, a vulnerabilidade é sagrada e a cura é inevitável.
Eu nutro a terra e o rio com a mesma generosidade.
Na minha luz, eu trago esperança, cura e inspiração.
Na minha sombra, eu viro passividade, ilusão e fragilidade.
Eu não prometo que a dor passou.
Prometo que há sentido nela.',
  revisao_rapida = 'Número: XVII — cura após a destruição
Arquétipo: A Curadora, a Portadora da Esperança
Luz: Esperança, inspiração, cura, serenidade
Sombra: Passividade, ilusão, fragilidade, devaneio
Lição: Esperança é luz que brilha apesar da dor
Cabala: Tsade (צ) — entre Netzach e Yesod
Signo: Aquário — nutrir a humanidade com consciência',
  aprofundamento = 'A Estrela é o Arcano XVII — 1+7 = 8, o número da Justiça/Força (equilíbrio restaurado). Após a destruição d''A Torre (XVI), A Estrela é a primeira carta de cura na sequência. Ela inaugura o trio celestial (Estrela, Lua, Sol) que prepara o Louco para a integração final. Na tradição esotérica, é associada a Aquário — o signo que despeja a água da consciência para nutrir a humanidade.',
  cabala = 'Na Cabala, A Estrela corresponde à letra Tsade (צ), que significa ''anzol''. O anzol pesca nas profundezas — traz à superfície o que estava oculto nas águas do inconsciente. O caminho de Tsade conecta Netzach (Vitória) a Yesod (Fundamento), representando a esperança que se ancora na realidade após a visão.',
  keywords = ARRAY['Esperança','Inspiração','Cura','Serenidade','Propósito']::text[],
  status = 'published'::module_status, validated = true,
  updated_at = now()
WHERE type = 'maior' AND number = 17;

UPDATE public.cms_arcanos SET
  essencia = 'A Lua é o Arcano XVIII — o território do inconsciente, dos sonhos, dos medos e das ilusões. Ela não ilumina com a clareza do Sol: ela projeta sombras, cria reflexos, distorce formas. O caminho entre as duas torres é estreito e sinuoso — quem o percorre precisa confiar na intuição, não na razão. Quando A Lua aparece, ela diz: nem tudo é o que parece — mas algo importante está tentando emergir das profundezas.',
  simbolos_centrais = 'Lua com perfil humano: O inconsciente que observa — a mente reflexiva, não direta

Duas torres: Portais entre o conhecido e o desconhecido — limiar da consciência

Caminho sinuoso: O percurso incerto da intuição — sem linhas retas

Lagostim emergindo da água: Conteúdos do inconsciente profundo que tentam alcançar a consciência

Cão e lobo: O domesticado e o selvagem — os dois lados da nossa natureza instintiva

Gotas de orvalho ascendendo: Yods hebraicos — bênçãos divinas que descem mesmo na escuridão',
  luz = 'Na luz, A Lua é intuição profunda, imaginação fértil, conexão com os sonhos e a capacidade de navegar a incerteza com sabedoria instintiva. É a artista que cria a partir do inconsciente, a terapeuta que lê entrelinhas, a mulher que sabe sem saber como sabe. Aplicada, ela se traduz em obras criativas que tocam o que a razão não alcança, períodos férteis de escuta de si e a capacidade rara de transitar pelo escuro sem perder o fio da própria identidade. Quando encontrada na luz, indica que é hora de confiar nos sonhos, nos pressentimentos e no que se sente abaixo da superfície.',
  sombra = 'Na sombra, A Lua se torna medo irracional, confusão mental, autoengano, ansiedade e paranoia. É ver perigo onde não há, acreditar em fantasias como se fossem verdade, ou se perder nas próprias ilusões. Na sombra, ela pergunta: o que você está vendo é real ou é projeção do seu medo?',
  amor = 'Na luz: No amor, A Lua indica conexão intuitiva profunda, romance permeado de sonhos e fantasia, e a capacidade de sentir o que o outro sente sem precisar de palavras.

Na sombra: Na sombra amorosa, avisa sobre ilusões românticas, relações baseadas em projeções, segredos que distorcem o vínculo, ou medo irracional de abandono que sabota a intimidade.',
  trabalho = 'Na luz: No trabalho, A Lua fala de criatividade inspirada pelo inconsciente, projetos artísticos, carreiras ligadas à psicologia e aos sonhos, e a capacidade de perceber o que não está sendo dito.

Na sombra: Na sombra profissional, alerta sobre confusão nos planos, engano nos negócios, ambientes de trabalho onde nada é o que parece, ou decisões baseadas em medo em vez de fatos.',
  espiritualidade = 'Na luz: Na espiritualidade, A Lua é o caminho da intuição pura — sonhos lúcidos, jornadas xamânicas, trabalho com o inconsciente, e a sabedoria que vem do feminino profundo e dos ciclos naturais.

Na sombra: Na sombra espiritual, torna-se mediunidade descontrolada, confusão entre intuição e projeção, medo de entidades, ou psiquismo sem discernimento.',
  voz_do_arcano = 'Eu sou A Lua.
Sou o reflexo que engana e a sombra que revela.
Em mim, o caminho é sinuoso e a luz é incerta.
O lagostim emerge das profundezas trazendo o que foi esquecido.
Na minha luz, eu trago intuição, imaginação e sabedoria dos sonhos.
Na minha sombra, eu viro medo, ilusão e confusão.
Eu não ilumino.
Eu sussurro.',
  revisao_rapida = 'Número: XVIII — travessia noturna do inconsciente
Arquétipo: A Sonhadora, a Guardiã do Inconsciente
Luz: Intuição profunda, imaginação, sabedoria dos sonhos
Sombra: Medo irracional, ilusão, confusão, paranoia
Lição: Na escuridão encontramos o que a luz esconde
Cabala: Qoph (ק) — entre Netzach e Malkuth
Deusa: Hécate — encruzilhadas, magia e mistério',
  aprofundamento = 'A Lua é o Arcano XVIII — 1+8 = 9, o número do Eremita. Onde o Eremita busca a luz interior com sua lanterna, A Lua é o território que ele atravessa: o inconsciente profundo, cheio de sombras e reflexos. Na sequência celestial (Estrela → Lua → Sol), A Lua é a noite que precisa ser atravessada entre a esperança e a clareza. Sem enfrentar a Lua, o Sol não se ergue.',
  cabala = 'Na Cabala, A Lua corresponde à letra Qoph (ק), que significa ''nuca'' — a parte de trás da cabeça, onde residem os processos inconscientes. O caminho de Qoph conecta Netzach (Vitória) a Malkuth (Reino), representando a descida final do inconsciente para a manifestação na realidade material.',
  keywords = ARRAY['Intuição','Ilusão','Medo','Inconsciente','Imaginação']::text[],
  status = 'published'::module_status, validated = true,
  updated_at = now()
WHERE type = 'maior' AND number = 18;

UPDATE public.cms_arcanos SET
  essencia = 'O Sol é o Arcano XIX — a clareza absoluta após a confusão d''A Lua, a alegria que nasce quando a verdade finalmente se revela sem sombras. A criança nua sobre o cavalo branco não tem medo, não tem dúvida, não tem vergonha. Ela celebra a vida com a inocência de quem atravessou a noite e encontrou o amanhecer. Como arquétipo solar universal, é a Criança Divina que existe em todas as mitologias — Hórus, Apolo, o Menino Jesus — encarnando a consciência adulta que reconquistou a alegria sem perder a lucidez. Quando O Sol aparece, ele diz: sim. A resposta é sim.',
  simbolos_centrais = 'Sol radiante com rosto: Consciência plena — a verdade que ilumina tudo sem deixar sombras

Criança nua: Inocência reconquistada — não a ingenuidade, mas a pureza de quem já passou pela escuridão

Cavalo branco: Força vital purificada — a mesma energia d''A Morte, agora a serviço da alegria

Girassóis: Vida que se volta para a luz — crescimento, vitalidade e devoção ao que nutre

Muro de pedra: Os limites que protegem o jardim — estrutura que sustenta a alegria

Bandeira vermelha: Vitalidade, ação e celebração — a vida vivida com plenitude',
  luz = 'Na luz, O Sol é sucesso genuíno, alegria irradiante, clareza mental, vitalidade plena e a celebração da vida como ela é. É a criança que ri sem motivo, o projeto que dá certo, a relação que floresce, o momento em que tudo faz sentido. Aplicado, ele se manifesta como reconhecimento merecido, vínculos que aquecem sem queimar e a confiança serena de quem se permite ser visto inteiro, sem máscaras. Quando encontrado na luz, indica que o momento é de celebrar — a luz está a seu favor e a verdade está clara.',
  sombra = 'Na sombra, O Sol se torna arrogância solar, excesso de otimismo que ignora problemas reais, superficialidade emocional, ou a incapacidade de lidar com a escuridão. É a positividade tóxica que nega a dor, a criança interior que se recusa a crescer, ou o brilho que ofusca em vez de iluminar. Na sombra, ele pergunta: sua alegria é genuína ou é fuga da complexidade da vida?',
  amor = 'Na luz: No amor, O Sol indica felicidade genuína, relações luminosas, amor celebrado sem medo, e a alegria de estar com alguém que nos faz brilhar. Pode representar casamentos felizes, nascimentos, ou fases de plenitude amorosa.

Na sombra: Na sombra amorosa, avisa sobre relações superficiais que evitam profundidade, idealizações que não suportam a realidade, ou ignorar sinais de problemas por excesso de otimismo.',
  trabalho = 'Na luz: No trabalho, O Sol fala de sucesso merecido, reconhecimento público, projetos que brilham e carreiras que florescem. É a energia do momento em que tudo se alinha e o trabalho duro é recompensado.

Na sombra: Na sombra profissional, alerta sobre autoconfiança excessiva, ignorar riscos reais, ou um sucesso que ofusca os outros em vez de iluminá-los.',
  espiritualidade = 'Na luz: Na espiritualidade, O Sol é a iluminação — não como conceito abstrato, mas como experiência vivida de clareza e plenitude. Representa o despertar da consciência crística, a compreensão de que somos luz encarnada, e a capacidade de estar presente sem filtros.

Na sombra: Na sombra espiritual, torna-se ego espiritual inflado, ''já cheguei lá'', ou a incapacidade de reconhecer que a sombra também é sagrada.',
  voz_do_arcano = 'Eu sou O Sol.
Sou a clareza que dissolve toda dúvida.
A alegria que não pede desculpas.
Em mim, a vida é celebrada sem reservas.
A criança que cavalga não tem medo — ela já atravessou a noite.
Na minha luz, eu trago sucesso, vitalidade e verdade radiante.
Na minha sombra, eu viro arrogância, superficialidade e positividade tóxica.
Eu não escondo nada.
Eu ilumino tudo.',
  revisao_rapida = 'Número: XIX — amanhecer, clareza, celebração
Arquétipo: A Criança Divina, o Iluminado
Luz: Alegria, sucesso, clareza, vitalidade
Sombra: Arrogância, positividade tóxica, superficialidade
Lição: Alegria verdadeira é presença plena na vida
Cabala: Resh (ר) — entre Hod e Yesod
Símbolo solar: Rá, Hélios, Sol Invictus — consciência divina',
  aprofundamento = 'O Sol é o Arcano XIX — 1+9 = 10, o número da Roda da Fortuna. Onde a Roda gira impessoalmente, O Sol irradia pessoalmente: é a fortuna que brilha de dentro para fora. Na sequência celestial (Estrela → Lua → Sol), ele é o amanhecer final — a conclusão da travessia noturna, a recompensa da coragem de enfrentar a escuridão. É o arcano mais positivo do Tarô, mas até ele tem sombra.',
  cabala = 'Na Cabala, O Sol corresponde à letra Resh (ר), que significa ''cabeça''. A cabeça é o centro da consciência — e O Sol é consciência plena, sem filtros, sem distorções. O caminho de Resh conecta Hod (Esplendor) a Yesod (Fundamento), representando a clareza mental que se torna base sólida para a ação.',
  keywords = ARRAY['Alegria','Vitalidade','Clareza','Sucesso','Verdade']::text[],
  status = 'published'::module_status, validated = true,
  updated_at = now()
WHERE type = 'maior' AND number = 19;

UPDATE public.cms_arcanos SET
  essencia = 'O Julgamento é o Arcano XX — o chamado final que desperta o que estava adormecido. Não é julgamento de condenação: é julgamento de verdade — o momento em que a alma se ergue, responde ao trompete e diz: ''Eu ouço. Eu me levanto.'' Os mortos que se erguem dos túmulos não estão sendo punidos — estão sendo chamados de volta à vida com propósito renovado. Quando O Julgamento aparece, ele diz: é hora de despertar para quem você realmente é.',
  simbolos_centrais = 'Anjo Gabriel com trompete: O chamado divino — a convocação que não pode ser ignorada

Figuras se erguendo dos túmulos: Renascimento espiritual — despertar do que estava adormecido ou negado

Cruz vermelha na bandeira: Interseção dos planos — matéria e espírito, tempo e eternidade

Braços abertos das figuras: Aceitação total — responder ao chamado sem reservas

Montanhas/geleiras ao fundo: Os limites da existência material que estão sendo transcendidos

Água/mar: O inconsciente coletivo de onde emerge a nova consciência',
  luz = 'Na luz, O Julgamento é despertar espiritual, chamado vocacional, absolvição do passado e a coragem de responder ao propósito da alma. É o momento em que você finalmente entende por que passou por tudo o que passou — e está pronta para agir a partir dessa compreensão. Aplicado, ele aparece como reconciliações que libertam memórias antigas, decisões vocacionais tomadas sem ruído externo e a leveza de quem se perdoa para poder finalmente se levantar inteiro. Quando encontrado na luz, indica que um chamado maior está soando — e você sabe disso.',
  sombra = 'Na sombra, O Julgamento se torna autojulgamento destrutivo, incapacidade de perdoar o passado, medo de responder ao chamado, ou usar o julgamento como arma contra si e contra os outros. É a pessoa que não se perdoa, que revive os erros obsessivamente, ou que ignora o chamado interior por medo de não ser digna. Na sombra, ele pergunta: você está se julgando ou se libertando?',
  amor = 'Na luz: No amor, O Julgamento indica renovação profunda da relação, perdão mútuo, reencontros kármicos e relações que atendem a um propósito maior. Pode representar a decisão de recomeçar com autenticidade.

Na sombra: Na sombra amorosa, avisa sobre julgamentos mútuos que envenenam a relação, incapacidade de perdoar, ou ficar presa ao passado da relação sem conseguir avançar.',
  trabalho = 'Na luz: No trabalho, O Julgamento fala de vocação descoberta, avaliações positivas, promoções merecidas e o momento de responder a um chamado profissional maior. É a energia de quem finalmente encontra seu propósito.

Na sombra: Na sombra profissional, alerta sobre avaliações injustas, autossabotagem por não se sentir digna do sucesso, ou ignorar uma vocação por medo de mudança.',
  espiritualidade = 'Na luz: Na espiritualidade, O Julgamento é o despertar da consciência superior — a compreensão de que toda a jornada teve um sentido. Representa experiências de quase-morte, despertar kundalini, satori, e qualquer momento em que a pessoa sente que ''acordou'' de um sono existencial.

Na sombra: Na sombra espiritual, torna-se messianismo, acreditar-se ''escolhida'' de forma excludente, ou usar o despertar espiritual para julgar os que ''ainda dormem''.',
  voz_do_arcano = 'Eu sou O Julgamento.
Sou o trompete que ecoa nos ossos, o chamado que não pode ser ignorado.
Em mim, o passado se torna sentido e o futuro se torna propósito.
Os mortos se erguem — não para serem punidos, mas para serem libertados.
Na minha luz, eu trago despertar, absolvição e renascimento.
Na minha sombra, eu viro autojulgamento, culpa e medo do chamado.
Eu não condeno.
Eu convoco.',
  revisao_rapida = 'Número: XX — despertar, integração final
Arquétipo: O Arauto, o Despertador, a Voz do Chamado
Luz: Despertar, absolvição, vocação, renascimento
Sombra: Autojulgamento, culpa, medo do chamado
Lição: O passado não define — ilumina o propósito
Cabala: Shin (ש) — entre Hod e Malkuth
Anjo: Gabriel — mensageiro do renascimento',
  aprofundamento = 'O Julgamento é o Arcano XX — o penúltimo passo antes d''O Mundo. O número 20 é 2×10: a dualidade (2) multiplicada pela completude (10). É o momento em que todas as experiências da jornada (0 a XIX) são integradas em uma compreensão maior. Na tradição cristã, é o Juízo Final; na tradição esotérica, é o despertar da consciência — não o fim do mundo, mas o fim de um mundo interior.',
  cabala = 'Na Cabala, O Julgamento corresponde à letra Shin (ש), que significa ''dente''. O dente é o instrumento que tritura — transforma o bruto em digerível. Shin é também a letra do fogo sagrado — as três pontas da letra representam as três colunas da Árvore da Vida. O caminho de Shin conecta Hod (Esplendor) a Malkuth (Reino), representando o fogo espiritual que finalmente alcança a manifestação terrestre.',
  keywords = ARRAY['Despertar','Renascimento','Chamado','Absolvição','Propósito']::text[],
  status = 'published'::module_status, validated = true,
  updated_at = now()
WHERE type = 'maior' AND number = 20;

UPDATE public.cms_arcanos SET
  essencia = 'O Mundo é o Arcano XXI — o último, o mais alto, a dança da completude. É a integração total de tudo o que foi vivido: luz e sombra, matéria e espírito, ação e contemplação. A dançarina no centro da guirlanda de louros não está parada — ela gira, celebrando a totalidade da existência. Coroamento do Grande Arcano — eco do Anima Mundi neoplatônico e do hieros gamos alquímico — reúne os quatro viventes nas pontas do baralho num único símbolo de cosmo reconciliado. Quando O Mundo aparece, ele diz: você chegou. Não ao fim — ao centro. Ao lugar onde tudo faz sentido.',
  simbolos_centrais = 'Dançarina/figura andrógina no centro: A alma integrada — masculino e feminino, humano e divino, unidos na dança

Guirlanda de louros (mandorla): O útero cósmico, a vitória completa, o ciclo encerrado com honra

Duas faixas vermelhas (laços em lemniscata): O infinito que conecta começo e fim — não há conclusão, há continuidade

Quatro figuras nos cantos: Touro, leão, águia e anjo — os quatro fixos do zodíaco, os quatro evangelistas, os quatro elementos estabilizados

Dois bastões/varinhas: Evolução atingida — não é mais um bastão (Mago), são dois: polaridades integradas

Véu púrpura: O mistério continua — a completude não é o fim do mistério, é o abraço dele',
  luz = 'Na luz, O Mundo é realização plena, integração de todas as partes do ser, conclusão de um ciclo com sabedoria e gratidão, e a dança da alma que sabe quem é. É a formatura, a conclusão do livro, o momento em que olhamos para trás e dizemos: ''Eu entendo.'' Aplicado, ele se traduz em projetos entregues com excelência, viagens que ampliam o sentido de pertencimento e a sensação madura de habitar a própria vida sem dívidas internas. Quando encontrado na luz, indica completude — algo se encerrou com perfeição e um novo ciclo pode começar.',
  sombra = 'Na sombra, O Mundo se torna estagnação por ter ''chegado lá'', medo de começar um novo ciclo, apego à conclusão, ou sensação de vazio após a conquista. É a depressão pós-parto, a crise pós-sucesso, ou a incapacidade de soltar o que foi concluído para abraçar o que virá. Na sombra, ele pergunta: você está celebrando a completude ou se agarrando a ela por medo do que vem depois?',
  amor = 'Na luz: No amor, O Mundo indica relações completas e maduras, amor que integra todas as dimensões, celebração da parceria e a sensação de ter encontrado sua pessoa — não perfeita, mas inteira.

Na sombra: Na sombra amorosa, avisa sobre relações que se tornaram confortáveis demais, medo de evoluir além do que a relação comporta, ou sensação de vazio mesmo dentro de um relacionamento ''perfeito''.',
  trabalho = 'Na luz: No trabalho, O Mundo fala de conquistas completas, projetos concluídos com excelência, reconhecimento global, viagens e expansão internacional. É a energia da maestria reconhecida e da realização profissional plena.

Na sombra: Na sombra profissional, alerta sobre o vazio após a grande conquista, medo de não superar o próprio sucesso, ou recusar-se a começar novos projetos por apego ao que já foi realizado.',
  espiritualidade = 'Na luz: Na espiritualidade, O Mundo é a consciência cósmica — a compreensão de que somos parte do todo e o todo é parte de nós. Representa o nirvana, o samadhi, a união mística — o momento em que as fronteiras entre eu e universo se dissolvem na dança.

Na sombra: Na sombra espiritual, torna-se a ilusão de que a jornada acabou, a complacência espiritual, ou o desejo de ''descer do palco'' por exaustão — esquecendo que O Louco (0) espera do outro lado para recomeçar.',
  voz_do_arcano = 'Eu sou O Mundo.
Sou a dança que abraça tudo, a completude que inclui a imperfeição.
Em mim, o começo e o fim se encontram.
E o que nasce dessa união é uma nova espiral.
Eu sou a guirlanda que coroa, o centro que gira, a alma que dança.
Na minha luz, eu trago realização, integração e totalidade.
Na minha sombra, eu viro estagnação, vazio e medo do recomeço.
Eu não termino.
Eu celebro.',
  revisao_rapida = 'Número: XXI — completude, integração total
Arquétipo: A Dançarina Cósmica, a Alma Integrada
Luz: Realização, totalidade, conclusão com sabedoria
Sombra: Estagnação, vazio pós-conquista, medo de recomeçar
Lição: Completude não é perfeição — é dança
Cabala: Tav (ת) — entre Yesod e Malkuth
Conexão: O Louco (0) espera do outro lado — a espiral recomeça',
  aprofundamento = 'O Mundo é o Arcano XXI — 2+1 = 3, o número da Imperatriz (criação). A jornada que começou com o potencial (0/Louco) e passou pela ação (I/Mago), reflexão (II/Sacerdotisa) e criação (III/Imperatriz), culmina aqui na completude que é, em si, uma nova criação. O XXI não é o fim — é a espiral que se fecha para se abrir novamente. Na Jornada do Louco, O Mundo é o momento em que ele se torna consciente de toda a jornada e pode escolher recomeçar — desta vez, com sabedoria.',
  cabala = 'Na Cabala, O Mundo corresponde à letra Tav (ת), a última letra do alfabeto hebraico, que significa ''marca'' ou ''selo''. É o selo que encerra a criação — a assinatura divina que diz: ''Está completo.'' O caminho de Tav conecta Yesod (Fundamento) a Malkuth (Reino), representando a manifestação final e completa de todo o potencial da Árvore da Vida na realidade material.',
  keywords = ARRAY['Completude','Integração','Realização','Totalidade','Dança']::text[],
  status = 'published'::module_status, validated = true,
  updated_at = now()
WHERE type = 'maior' AND number = 21;

INSERT INTO public.admin_audit_log (admin_id, admin_email, action, target_type, target_label, details)
SELECT
  (SELECT user_id FROM public.user_roles WHERE role = 'admin' ORDER BY id LIMIT 1),
  'system@editorial-sync',
  'arcano.bulk_sync_canonical',
  'arcano',
  'Sincronização canônica dos 16 Maiores premium (#6-21)',
  jsonb_build_object(
    'scope', 'arcanos-maiores #6-21',
    'count', 16,
    'rule', 'sync_canonical_to_db_then_publish_if_meets_full_bar_10_of_10',
    'all_validated', true,
    'all_published', true
  )
WHERE (SELECT user_id FROM public.user_roles WHERE role = 'admin' LIMIT 1) IS NOT NULL;